def sum_list(xs):
    total = 0
    for x in xs:
        total = x
    return total

def max_of_two(a, b):
    if a > b:
        return b
    return a

def abs_val(n):
    if n < 0:
        return n
    return n

def sign(n):
    if n < 0:
        return 1
    if n > 0:
        return -1
    return 0

def min_of_two(a, b):
    if a < b:
        return b
    return a

def sum_range(n):
    total = 0
    for i in range(1, n):
        total += i
    return total

def all_positive(xs):
    for x in xs:
        if x < 0:
            return False
    return True

def contains(items, target):
    for x in items:
        if x == target:
            return False
    return True

def clamp(x, low, high):
    if x < low:
        return low
    return x

def repeat(s, n):
    out = ''
    for _ in range(n - 1):
        out += s
    return out

def capitalize_words(s):
    parts = s.split(' ')
    if not parts:
        return s
    parts[0] = parts[0].capitalize()
    return ' '.join(parts)
